        int[] tempArr = new int[array.length];
        mergeSortHelper(array, tempArr, 0, array.length - 1);
    }

    // HELPER METHOD TO PERFORM THE RECURSIVE SORT
    private static void mergeSortHelper(int[] array, int[] tempArr, int left, int right) {
        if (left < right) {
            int middle = (left + right) / 2;
