#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Open the PDF file
my $pdf = PDF::API2->open('input.pdf');

# Create a TextExtractor object
my $extractor = PDF::Text::Simple->new($pdf);

# Extract all text from the PDF
my @all_text = $extractor->extract_all();

# Loop through the extracted text to find specific data
foreach my $text (@all_text) {
    if ($text =~ /date:\s*(\d{2}\/\d{2}\/\d{4})/) {
        print "Date: $1\n";
    } elsif ($text =~ /author:\s*(\w+)/) {
        print "Author: $1\n";
    } elsif ($text =~ /\b\d+\s*[\w\s]+\b/) {
        # Example condition to extract table rows
        print "Table Data: $text\n";
    }
}

# Clean up and close the PDF file
$pdf->end();
